import axios from "axios";

const API_BASE_URL = process.env.REACT_APP_API_URL || "http://localhost:5000/api";

const apiClient = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    "Content-Type": "application/json",
  },
});

// Customer APIs
export const getCustomers = () => apiClient.get("/customers");
export const addCustomer = (payload) => apiClient.post("/customers", payload);

// Transaction APIs
export const addTransaction = (payload) => apiClient.post("/transactions", payload);
export const getTransactions = (customerId) => apiClient.get(`/transactions/${customerId}`);

export default apiClient;
